module mux_1to2_async_rst(
    input clk,
    input rst,
    input din0,
    input din1,
    input sel,
    output dout
);

    reg invalid_dout;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            invalid_dout <= 0;
        end else begin
            if (sel) begin
                invalid_dout <= din1;
            end else begin
                invalid_dout <= din0;
            end
        end
    end

    assign dout = invalid_dout;

endmodule
